st.set_page_config(
    page_title="Wings of Glory Bingo",
    page_icon="✦",
    layout="centered",
    initial_sidebar_state="collapsed",
)

st.markdown("""
<style>
header[data-testid="stHeader"] { display: none; }
#MainMenu { visibility: hidden; }
footer { visibility: hidden; }
.block-container { padding: 0 !important; max-width: 100% !important; }
.stApp { background: #06070c; }
iframe { display: block; }
</style>
""", unsafe_allow_html=True)

html = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<style>\n:root{\n  --bg:#06070c;\n  --navy:#182238;\n  --navy2:#202c47;\n  --gold:#d4a22f;\n  --gold2:#9a6b0d;\n  --text:#e8edf5;\n  --muted:#9ea9ba;\n  --mark:#2f8f57;\n  --free:#3151a3;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  background:#06070c;\n  color:var(--text);\n  font-family:Arial, \"Segoe UI\", sans-serif;\n  overflow-x:hidden;\n}\n.app{\n  width:min(96vw,760px);\n  margin:0 auto;\n  padding:10px 8px 20px;\n}\n.header{text-align:center;margin:0 0 6px}\n.title{\n  color:var(--gold);\n  font-weight:900;\n  font-size:34px;\n  line-height:1;\n  text-shadow:0 0 6px rgba(212,162,47,.35);\n}\n.subtitle{\n  margin-top:5px;\n  color:#bac7d8;\n  font-weight:900;\n  font-size:18px;\n  letter-spacing:.08em;\n  text-transform:uppercase;\n}\n.toolbar{\n  display:flex;\n  justify-content:center;\n  gap:4px;\n  margin:8px auto 7px;\n}\nbutton,select{\n  height:34px;\n  border:1px solid #4d3508;\n  background:#211707;\n  color:var(--gold);\n  font-weight:800;\n  font-size:14px;\n  padding:0 14px;\n  cursor:pointer;\n}\nbutton:hover,select:hover{filter:brightness(1.15)}\nbutton:active{filter:brightness(.9)}\n.line{\n  height:4px;\n  background:#8e28bd;\n  margin:0 auto 8px;\n  box-shadow:0 0 6px rgba(142,40,189,.8);\n}\n.boards{\n  display:grid;\n  justify-content:center;\n  gap:12px;\n}\n.boards.one{grid-template-columns:minmax(320px, min(92vmin, 620px))}\n.boards.two,.boards.three,.boards.four{\n  grid-template-columns:repeat(2,minmax(300px,1fr));\n  width:min(96vw,900px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.board-shell{\n  border:3px solid var(--gold);\n  background:#221909;\n  box-shadow:none;\n  padding:0;\n}\n.board{\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  gap:2px;\n  background:#2b2416;\n  aspect-ratio:1/1;\n}\n.cell{\n  border:0;\n  background:var(--navy);\n  color:var(--text);\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  text-align:center;\n  padding:6px;\n  font-weight:800;\n  font-size:clamp(10px,1.35vw,15px);\n  line-height:1.12;\n  cursor:pointer;\n  user-select:none;\n  transition:filter .08s ease, background .08s ease;\n  overflow:hidden;\n}\n.cell:nth-child(even){background:var(--navy2)}\n.cell:hover{filter:brightness(1.12)}\n.cell.free{\n  background:var(--free)!important;\n  color:#ffe08a;\n  font-style:italic;\n  font-size:clamp(15px,2vw,22px);\n  cursor:default;\n}\n.cell.marked{\n  background:var(--mark)!important;\n  color:#f2fff6;\n}\n.cell.rolling:not(.free){\n  filter:brightness(1.25);\n}\n.modal-backdrop{\n  position:fixed;\n  inset:0;\n  background:rgba(0,0,0,.72);\n  display:none;\n  align-items:center;\n  justify-content:center;\n  z-index:20;\n  padding:20px;\n}\n.modal-backdrop.show{display:flex}\n.modal{\n  width:min(92vw,360px);\n  background:#111827;\n  border:2px solid var(--gold);\n  padding:16px;\n}\n.modal h2{\n  color:var(--gold);\n  margin:0 0 10px;\n  font-size:26px;\n}\n.modal p{margin:7px 0;font-weight:700}\n.close{width:100%;margin-top:12px}\n.bingo-modal .modal{text-align:center}\n.bingo-modal h2{font-size:54px;text-shadow:0 0 8px var(--gold)}\n@media(max-width:760px){\n  .boards.two,.boards.three,.boards.four{\n    grid-template-columns:1fr;\n    width:min(96vw,620px);\n  }\n  .title{font-size:30px}\n  .subtitle{font-size:15px}\n}\n</style>\n</head>\n<body>\n<div class=\"app\">\n  <div class=\"header\">\n    <div class=\"title\">\u2726 Wings of Glory \u2726</div>\n    <div class=\"subtitle\">Low Rank Bingo</div>\n  </div>\n\n  <div class=\"toolbar\">\n    <button onclick=\"rollBoards()\">Roll</button>\n    <button onclick=\"resetMarks()\">Reset</button>\n    <button onclick=\"openRules()\">Bingo?</button>\n    <button onclick=\"toggleFull()\">Full</button>\n    <select onchange=\"setBoardCount(this.value)\">\n      <option value=\"1\">1</option>\n      <option value=\"2\">2</option>\n      <option value=\"3\">3</option>\n      <option value=\"4\">4</option>\n    </select>\n  </div>\n\n  <div class=\"line\"></div>\n  <div id=\"boards\" class=\"boards one\"></div>\n</div>\n\n<div id=\"rulesModal\" class=\"modal-backdrop\" onclick=\"closeRules(event)\">\n  <div class=\"modal\">\n    <h2>Rules</h2>\n    <p>Click a square when it happens.</p>\n    <p>Free space starts marked.</p>\n    <p>5 in a row wins.</p>\n    <p>Rows, columns, diagonals count.</p>\n    <button class=\"close\" onclick=\"hideRules()\">Close</button>\n  </div>\n</div>\n\n<div id=\"bingoModal\" class=\"modal-backdrop bingo-modal\" onclick=\"hideBingo()\">\n  <div class=\"modal\">\n    <h2>BINGO!</h2>\n    <button class=\"close\" onclick=\"hideBingo()\">Close</button>\n  </div>\n</div>\n\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\nlet boards=[];\nlet marked=[];\nlet boardCount=1;\nlet rolling=false;\n\nfunction shuffle(arr){\n  const a=[...arr];\n  for(let i=a.length-1;i>0;i--){\n    const j=Math.floor(Math.random()*(i+1));\n    [a[i],a[j]]=[a[j],a[i]];\n  }\n  return a;\n}\nfunction makeBoard(){\n  const shuffled=shuffle(ITEMS);\n  const board=[];\n  let idx=0;\n  for(let i=0;i<25;i++){\n    board.push(i===12 ? \"FREE SPACE\" : shuffled[idx++]);\n  }\n  return board;\n}\nfunction classForCount(){\n  if(boardCount===1)return\"one\";\n  if(boardCount===2)return\"two\";\n  if(boardCount===3)return\"three\";\n  return\"four\";\n}\nfunction setBoardCount(n){\n  boardCount=Math.max(1,Math.min(4,Number(n)));\n  while(boards.length<boardCount){\n    boards.push(makeBoard());\n    marked.push(new Set([12]));\n  }\n  while(boards.length>boardCount){\n    boards.pop();\n    marked.pop();\n  }\n  render();\n}\nfunction render(){\n  const root=document.getElementById(\"boards\");\n  root.className=\"boards \"+classForCount();\n  root.innerHTML=\"\";\n  for(let b=0;b<boardCount;b++){\n    const shell=document.createElement(\"div\");\n    shell.className=\"board-shell\";\n    const board=document.createElement(\"div\");\n    board.className=\"board\";\n    for(let i=0;i<25;i++){\n      const cell=document.createElement(\"div\");\n      cell.className=\"cell\";\n      if(i===12)cell.classList.add(\"free\");\n      if(marked[b].has(i))cell.classList.add(\"marked\");\n      cell.textContent=boards[b][i];\n      cell.onclick=()=>toggleCell(b,i);\n      board.appendChild(cell);\n    }\n    shell.appendChild(board);\n    root.appendChild(shell);\n  }\n}\nfunction toggleCell(b,i){\n  if(i===12||rolling)return;\n  const boardEl=document.getElementById(\"boards\").children[b].querySelector(\".board\");\n  const cell=boardEl.children[i];\n  if(marked[b].has(i)){\n    marked[b].delete(i);\n    cell.classList.remove(\"marked\");\n  }else{\n    marked[b].add(i);\n    cell.classList.add(\"marked\");\n  }\n  if(hasBingo(marked[b]))showBingo();\n}\nfunction winLines(){\n  const lines=[];\n  for(let r=0;r<5;r++)lines.push([0,1,2,3,4].map(c=>r*5+c));\n  for(let c=0;c<5;c++)lines.push([0,1,2,3,4].map(r=>r*5+c));\n  lines.push([0,6,12,18,24]);\n  lines.push([4,8,12,16,20]);\n  return lines;\n}\nfunction hasBingo(set){\n  return winLines().some(line=>line.every(i=>set.has(i)));\n}\nfunction rollBoards(){\n  if(rolling)return;\n  rolling=true;\n  const cells=()=>Array.from(document.querySelectorAll(\".cell:not(.free)\"));\n  let steps=7;\n  function spin(step){\n    const temp=Array.from({length:boardCount},()=>makeBoard());\n    cells().forEach((cell,idx)=>{\n      const boardIndex=Math.floor(idx/24);\n      const innerIndex=idx%24;\n      const pool=temp[boardIndex].filter((_,i)=>i!==12);\n      cell.textContent=pool[innerIndex]||ITEMS[Math.floor(Math.random()*ITEMS.length)];\n      cell.classList.add(\"rolling\");\n      setTimeout(()=>cell.classList.remove(\"rolling\"),80);\n    });\n    if(step<steps){\n      setTimeout(()=>spin(step+1),70+step*12);\n    }else{\n      boards=Array.from({length:boardCount},()=>makeBoard());\n      marked=Array.from({length:boardCount},()=>new Set([12]));\n      rolling=false;\n      render();\n    }\n  }\n  spin(0);\n}\nfunction resetMarks(){\n  marked=Array.from({length:boardCount},()=>new Set([12]));\n  render();\n}\nfunction openRules(){document.getElementById(\"rulesModal\").classList.add(\"show\")}\nfunction hideRules(){document.getElementById(\"rulesModal\").classList.remove(\"show\")}\nfunction closeRules(e){if(e.target.id===\"rulesModal\")hideRules()}\nfunction showBingo(){document.getElementById(\"bingoModal\").classList.add(\"show\")}\nfunction hideBingo(){document.getElementById(\"bingoModal\").classList.remove(\"show\")}\nfunction toggleFull(){\n  const el=document.documentElement;\n  if(!document.fullscreenElement)el.requestFullscreen?.();\n  else document.exitFullscreen?.();\n}\ndocument.addEventListener(\"keydown\",e=>{\n  if(e.key===\"Escape\"){hideRules();hideBingo();}\n});\nboards=[makeBoard()];\nmarked=[new Set([12])];\nrender();\n</script>\n</body>\n</html>\n"

components.html(html, height=920, scrolling=True)
